export interface FeatureFlagEvaluateResponse {
    enabled: boolean;
}
export interface BatchFeatureFlagEvaluateInput {
    flagName: string;
    fallback?: boolean;
}
export interface BatchEvaluateFeatureFlagResponse {
    [flagName: string]: FeatureFlagEvaluateResponse;
}
export interface HarmonyApiFeatureFlags {
    /**
     * Evaluate a feature flag asynchronously.
     *
     * @param {String} flagName (required) the feature flag being evaluated
     * @param {boolean} fallback the fallback when the feature flag cannot be evaluated
     * @memberof window.harmony.api.featureFlags
     * @async
     */
    evaluateAsync: (flagName: string, fallback?: boolean) => Promise<FeatureFlagEvaluateResponse>;
    /**
     * Evaluates a list of feature flags asynchronously.
     * If no argument is passed in, evaluate all feature flags for the app.
     *
     * @param {Object[]} flags The flags to evaluate
     * @param {string} flags.flagName The feature flag name
     * @param {boolean} flags.fallback The fallback value
     * @memberof window.harmony.api.featureFlags
     */
    batchEvaluateAsync: (flags?: BatchFeatureFlagEvaluateInput[]) => Promise<BatchEvaluateFeatureFlagResponse>;
}
